    },
    {
      "source_requirement": "Trigger the transition from the Completed state to the Paid state only if the total amount due for the Campaign has been completely paid.",
      "rewritten_requirement": "The system shall trigger the transition from the Completed state to the Paid state only when the total amount due for the Campaign has been completely paid."
    },
    {
      "source_requirement": "Trigger the reflexive transition from the Completed state for any payment event that does not reduce the amount due to zero or less.",
      "rewritten_requirement": "The system shall trigger a reflexive transition from the Completed state for any payment event that does not reduce the amount due to zero or less."
    },
    {
      "source_requirement": "Modify the guard conditions of the Completed state if an overpayment results in automatic generation of a refund.",
      "rewritten_requirement": "The system shall modify the guard conditions of the Completed state when an overpayment results in automatic generation of a refund."
    }
  ]
}
